package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.apache.commons.csv.CSVFormat;

class CSVFormatTest {

    @Test
    void testGetTrim_DefaultFalse() {
        CSVFormat format = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false, false);
        assertFalse(format.getTrim());
    }

    @Test
    void testGetTrim_True() {
        CSVFormat format = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, true, false, false);
        assertTrue(format.getTrim());
    }

    @Test
    void testGetTrim_UsingWithTrimTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withTrim(true);
        assertTrue(format.getTrim());
    }

    @Test
    void testGetTrim_UsingWithTrimFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withTrim(false);
        assertFalse(format.getTrim());
    }
}
